INSERT INTO `accesorios` (`id`, `id_imagen`, `nombre`, `tipo`, `plataforma`, `anio`, `estado`, `precio`, `comentario`, `created_at`, `favorito`) VALUES
(1, 'df5bff91da7e2bbfcc24c30522e42d09', 'HORI D-Pad Controller (L) (Zelda)', 'Control', '26', 2018, 'Usado - Excelente', 30000, 'Este control es bien especial:\n✔️ Muy bueno para juegos retro o de pelea gracias a la cruceta real (tipo SNES/NES).\n❌ Pero es limitado: solo sirve en modo portátil y no tiene vibración, giroscopio ni NFC.\n\n👉 En resumen:\n\nSi juegas mucho MAME, NES, SNES o juegos 2D, es una mejora real.\nSi usas la Switch en TV o quieres funciones completas, no reemplaza un Joy-Con normal.', '2026-04-15 00:42:46', 0),
(2, '834f9188550ce074abc062014362979d', 'Hori Wireless SNES Classic Edition Super Nintendo Controller', 'Control', 'Otro', 2017, 'Usado - Excelente', 20000, 'Características principales\n📡 Inalámbrico (2.4 GHz)\nUsa un receptor USB/dongle que se conecta a la consola.\n🎮 Diseño tipo SNES + 6 botones\nTiene los 4 clásicos (A, B, X, Y) + 2 extra (tipo fighting).\nIdeal para juegos de pelea como Street Fighter.\n⚡ Funciones especiales\nTurbo configurable por botón\nModo slow motion\n🔋 Alimentación\nFunciona con 2 pilas AA (no incluidas)\n📏 Alcance\nAproximadamente 5–10 metros\n✔️ Licencia oficial Nintendo', '2026-04-15 01:35:34', 0),
(3, 'cee47cd7b341116adf116331f46a122d', 'Cargador Nintendo 3DS', 'Cargador', '48', 2009, 'Usado - Excelente', 20000, 'Comentario claro\n\n✔️ El cargador original es muy confiable y duradero (los típicos Nintendo que duran años).\n✔️ Además sirve para toda la familia 3DS, así que es súper reutilizable.\n\n❌ Los genéricos funcionan, pero:\n\nA veces cargan más lento\nPueden fallar antes\nNo tienen el mismo control de calidad\n\n👉 En resumen:\n\nCompra original si quieres algo seguro a largo plazo\nCompra genérico si necesitas algo barato rápido', '2026-04-15 01:39:07', 0),
(4, '011f79efd9ff727794b7cbc91e0ff09b', 'Base para figuras de Saint Seiya', 'Otro', 'Otro', 2018, 'Usado - Bueno', 15000, 'Saint Cloth Myth Display Stage Set\n🏢 Fabricante: Bandai\n🎯 Diseñada para líneas Myth Cloth / Myth Cloth EX\n🔧 Incluye:\nBase plástica\nBrazo articulado\nSoportes intercambiables\n\n✔️ Permite poses dinámicas (volando, ataques, etc.)\n✔️ Compatible con la mayoría de figuras Saint Seiya', '2026-04-15 01:59:53', 0),
(5, 'd0871f9527bd510694c59b569fa9f11b', 'Caja de Joycons', 'Control', '26', 2017, 'Usado - Excelente', 5000, '', '2026-05-09 03:02:39', 0);
INSERT INTO `amiibos` (`id`, `id_imagen`, `titulo`, `anio`, `estado`, `calificacion`, `precio`, `comentario`, `created_at`, `favorito`) VALUES
(5, 'bcf47f0b44d41e6511e53fe3e7d4c6c9', 'Rosalina Super Mario', 2016, 'Nuevo', '⭐⭐⭐⭐⭐', 34990, 'El amiibo de Rosalina destaca por su diseño elegante y fiel al personaje, especialmente en su versión con Luma, que añade un nivel extra de detalle. Es una figura muy apreciada por coleccionistas y fans de Super Mario Galaxy, tanto por su estética como por su compatibilidad con múltiples juegos. Aunque puede ser algo difícil de conseguir en ciertas versiones, sigue siendo una excelente adición para cualquier colección de amiibo.', '2026-04-14 02:23:27', 0),
(6, '19652ba08068970cb3f787620d3bf54d', 'Zelda - The Legend of Zelda: Breath of the Wild', 2017, 'Nuevo', '⭐⭐⭐⭐⭐', 35000, 'Los amiibo de Breath of the Wild son una colección de figuras que desbloquean contenido especial dentro del juego.\n\nIncluyen personajes como:\n\nLink (varias versiones)\nZelda\nBokoblin\nGuardian\n\nAl usarlos en el juego, puedes obtener:\n\nArmas y escudos especiales\nMateriales y comida\nCofres con recompensas aleatorias\nEquipamiento exclusivo (como el traje de Link clásico)\n\nAdemás, destacan por su calidad de diseño, especialmente el amiibo del Guardian, que tiene partes móviles.', '2026-04-14 02:35:09', 0),
(7, '42c54dca8b2c89d170d83bc3309a62e1', 'Luigi Super Smash Bros', 2014, 'Nuevo', '⭐⭐⭐⭐', 35000, 'El amiibo de Luigi basado en Super Smash Bros. presenta al personaje en una pose clásica de combate.\n\nAl usarlo en juegos compatibles, especialmente en Super Smash Bros. for Wii U y Super Smash Bros. Ultimate, puedes entrenar a Luigi como un luchador personalizado que aprende de tu estilo de juego.\n\nEste amiibo permite:\n\nGuardar progreso y habilidades\nSubir de nivel hasta 50\nDesbloquear contenido adicional en algunos juegos\n\nAunque no es de los amiibo más raros, sigue siendo una buena pieza para fans de Luigi y coleccionistas de amiibo.', '2026-04-14 03:02:32', 0),
(8, 'dab4b49a4ea481b5d560584cecc1b7f6', 'Shovel Knight', 2015, 'Nuevo', '⭐⭐⭐⭐⭐', 25000, 'El amiibo de Shovel Knight es una figura coleccionable con tecnología NFC que permite desbloquear contenido adicional en juegos compatibles.\n\nFue lanzado en 2015 y es especialmente importante porque fue el primer amiibo basado en un juego indie, desarrollado por Yacht Club Game', '2026-04-14 14:04:38', 0),
(9, '7b276005fde479e9563f68f2e2873f17', ' Link Majora’s Mask (The Legend of Zelda)', 2017, 'Nuevo', '⭐⭐⭐⭐⭐', 40000, 'Comentario claro\n\nEste amiibo es de los más valorados de Zelda:\n\n✔️ Diseño muy icónico (Majora’s Mask + Goron Mask)\n✔️ Tiene uno de los mejores drops en Breath of the Wild\n✔️ Muy buscado por coleccionistas\n\n❌ No siempre es fácil de encontrar a buen precio\n\n👉 En resumen:\nEs uno de los mejores amiibo de Link, tanto por estética como por utilidad en juegos.', '2026-04-15 02:01:17', 0),
(10, '440f1aa7e0e63d486b8206cc74e82185', 'Link Skyward Sword', 2017, 'Nuevo', '⭐⭐⭐⭐⭐', 30000, 'El amiibo de Link basado en The Legend of Zelda: Skyward Sword representa al héroe con la Espada Maestra y el Escudo Hyliano, en una pose clásica de combate.\n\nForma parte de la colección aniversario de Zelda y destaca por su fidelidad al diseño original del juego.\n\n🎮 Funcionalidad\n\nAl usarlo en juegos compatibles como The Legend of Zelda: Breath of the Wild:\n\n📦 Aparecen cofres con recompensas\n🏹 Materiales, armas y flechas\n🧥 Posibilidad de obtener el set del “Héroe del cielo” (ropa especial)\n⚔️ Armas exclusivas como la espada divina\n\n👉 También funciona en varios juegos más desbloqueando contenido adicional.', '2026-05-01 01:04:47', 0),
(11, '9681d83fd39727bb1a189aef2795cdb7', 'Link (Twilight Princess)', 2016, 'Usado - Excelente', '⭐⭐⭐⭐⭐', 50000, 'El amiibo de Link basado en Twilight Princess muestra una versión más seria y realista del personaje, con detalles en la armadura, la Espada Maestra y el Escudo Hyliano.\n\nEs muy apreciado por su estética más “oscura” comparada con otras versiones de Link.\n\n🎮 Funcionalidad\n\nAl usarlo en juegos compatibles como The Legend of Zelda: Breath of the Wild:\n\n📦 Genera cofres con recompensas\n⚔️ Puede desbloquear la Epona (montura especial)\n🧥 Posibilidad de obtener el traje de Twilight Princess\n\n👉 También tiene funciones en otros juegos de Zelda y Nintendo.', '2026-05-01 01:06:34', 0);
