(90, 50, '98649eb5e232b3af2b094718673e4939', 'Famicom mini', 1, 1, 1, 1, 'Usado - Excelente', 100000, '🧩 Juegos incluidos\n\nIncluye 30 juegos clásicos de Famicom, como:\n\nSuper Mario Bros.\nSuper Mario Bros. 3\nThe Legend of Zelda\nMetroid\nDonkey Kong\nKirby’s Adventure\nCastlevania\nMega Man 2', '🧩 Juegos incluidos\n\nIncluye 30 juegos clásicos de Famicom, como:\n\nSuper Mario Bros.\nSuper Mario Bros. 3\nThe Legend of Zelda\nMetroid\nDonkey Kong\nKirby’s Adventure\nCastlevania\nMega Man 2', '2026-03-21 01:16:48', 0),
(97, 56, 'c58c094726b2e8e47c62ef3076346255', 'Atari Flashback 1', 1, 1, 1, 1, 'Usado - Excelente', 50000, 'El Atari Flashback 1 fue la primera consola de la serie Flashback, creada para revivir los clásicos de Atari en formato moderno.\n\n👉 Características principales:\n\nIncluye 20 juegos integrados (no usa cartuchos)\nDiseño inspirado en la Atari 7800\nIncluye 2 joysticks tipo clásico\nConexión directa a TV (plug & play)', '', '2026-05-03 22:03:48', 0);
