INSERT INTO `juegos` (`id`, `titulo`, `plataforma_id`, `id_imagen`, `region`, `formato`, `estado`, `cartucho`, `manual`, `caja`, `valor`, `lanzamiento`, `genero`, `desarrollador`, `publicador`, `fecha_compra`, `notas`, `created_at`, `comentario`, `puntuacion`, `favorito`) VALUES
(1, 'Super Smash Bros Ultimate', 26, 'bf07808191890cf83bb001a5e0e79494', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 36000, 2018, 'Lucha', 'Sora Ltd.', 'Nintendo', NULL, NULL, '2026-01-10 03:48:38', 'Super Smash Bros. Ultimate reúne a personajes legendarios de videojuegos en combates frenéticos y competitivos.\n\nSu gran atractivo es su enorme plantilla:\n\n89 luchadores jugables (incluyendo DLC)\nTodos los personajes de entregas anteriores regresan\nEscenarios clásicos remasterizados\nMúsica de cientos de juegos icónicos\n\nIncluye personajes de sagas como:\n\nSuper Mario\nThe Legend of Zelda\nFinal Fantasy\nStreet Fighter\nTekken\nPersona', 5, 0),
(2, 'Astral Chains', 26, '63f0537ec4c078d37a31c744a7e3a182', 'NTSC-U', '', 'Usado - Excelente', 1, 1, 1, 36000, 2019, 'Hack and Slash', 'PlatinumGames', 'Nintendo', NULL, NULL, '2026-01-10 03:48:38', 'En Astral Chain controlas a un policía futurista de una unidad especial llamada Neuron, acompañado por criaturas biomecánicas conocidas como Legions.\n\nLa historia ocurre en una ciudad futurista amenazada por seres interdimensionales llamados Chimera.\n\nEl combate mezcla:\n\n⚔️ Acción rápida estilo hack and slash\n🤖 Control simultáneo del personaje y la Legion\n🕵️ Investigación policial y exploración\n🎮 Características destacadas\n🎨 Estilo anime futurista\n⚡ Combate muy dinámico\n🎵 Banda sonora intensa\n👥 Cooperativo local opcional\n🧠 Sistema de combate estratégico usando cadenas y Legions', 5, 0),
(3, 'Super Mario 3D All Stars', 26, '865d97cf2acead333c42a8fc8e0f1bc0', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 80000, 2020, 'Plataformas', 'Nintendo EPD', 'Nintendo', NULL, NULL, '2026-01-10 03:48:38', NULL, NULL, 0),
