(10, 'Teenage Mutant Ninja Turtles: The Cowabunga Collection', 26, '66d4295dcea82e804556453a2e7a3be6', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 37000, 2002, 'Beat \'em up', 'Digital Eclipse', 'Konami', NULL, NULL, '2026-01-10 03:48:38', '', 0, 0),
(11, 'Namco Museum: Arcade Pac', 26, '600e01bad8fed05f0011175f000985ca', 'NTSC-U', '', 'Usado - Excelente', 1, 1, 1, 37000, 2018, 'Arcade', 'Bandai Namco Studios', 'Bandai Namco Entertainment', NULL, NULL, '2026-01-10 03:48:38', 'Esta colección reúne clásicos arcade históricos de Namco junto con PAC-MAN Championship Edition 2 Plus, mezclando juegos retro con una versión moderna y frenética de Pac-Man.\n\nIncluye títulos como:\n\nPac-Man\nGalaga\nDig Dug\nSplatterhouse\nRolling Thunder\nSky Kid\nTank Force\nPac-Man Vs.\nGalaga ’88\n\nLa colección fue valorada positivamente por la nostalgia, la cantidad de clásicos y el modo portátil de Nintendo Switch, aunque algunos jugadores criticaron la ausencia de ciertos juegos icónicos de Namco.', 5, 0),
(12, 'Resident Evil Revelation Collection', 26, '1d01d0cc5fe333f797eee6a7db78a22b', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 37000, 2017, 'Survival Horror', 'Capcom', 'Capcom', NULL, NULL, '2026-01-10 03:48:38', NULL, NULL, 0),
