(47, 'Xenoblade Chronicles 2', 26, '819880dc58b71de92bb76fd03dea36a8', '', '', '', 1, 1, 1, 350000, 0, '', '', '', NULL, NULL, '2026-01-10 03:48:38', NULL, NULL, 0),
(48, 'Octopath Traveler', 26, '33a59790b891e62d69a4dc4c4744534b', 'PAL', NULL, 'Nuevo', 1, 1, 1, 100000, 2018, 'Rol (RPG)', 'Square Enix / Acquire', 'Square Enix', NULL, NULL, '2026-01-10 03:48:38', 'Descripción\n\nOctopath Traveler es un RPG donde eliges entre 8 personajes diferentes, cada uno con su propia historia, habilidades y camino.\n\n8 protagonistas\n8 historias independientes\nPuedes elegir el orden de la aventura\n\nEl juego se desarrolla en el mundo de Orsterra, combinando exploración, narrativa y combate estratégico.', 5, 0),
(49, 'Fire Embrem Warrior Special Edition', 26, 'eba350f4d2346e15fd3a89598d0a79e6', '', '', '', 1, 1, 1, 100000, 0, '', '', '', NULL, NULL, '2026-01-10 03:48:38', NULL, NULL, 0),
(50, 'Flashback 25 Anniversary', 26, '7340d309f75d4ea7df2eace90665118e', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 80000, 2018, 'Acción-Aventura', 'Paul Cuisset / Microids', 'Microids', NULL, NULL, '2026-01-10 03:48:38', 'Flashback 25th Anniversary es una reedición del clásico Flashback, considerado uno de los juegos más importantes de los años 90.\n\nLa historia sigue a Conrad B. Hart, un científico que despierta sin memoria en una luna de Saturno mientras es perseguido por enemigos. Debe sobrevivir, recuperar sus recuerdos y descubrir una conspiración alienígena.\n\nEsta versión incluye dos modos:\n\n🎮 Modo clásico: experiencia original de 1993\n⚡ Modo moderno: mejoras gráficas, sonido remasterizado, tutorial y función “rewind” para retroceder errores\n\nEl juego destaca por su estilo cinematográfico, animaciones realistas (usando motion capture) y mezcla de plataformas con puzzles y acción.', 4, 0),
(51, 'NieR:Automata The End of YoRHa Edition NSW', 26, 'fdf3265a3b094c64307994c100653e6f', '', '', '', 1, 1, 1, 40000, 0, '', '', '', NULL, NULL, '2026-01-10 03:48:38', NULL, NULL, 0),
