(122, 'Excitebike', 25, '81ec11092da04dad945a76f240e69855', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 0, 15000, 1985, 'Carreras', 'Uno de los primeros juegos de carreras de Nintendo.  Controlas una moto de motocross en pistas llenas de saltos, obstáculos y rampas.  Es simple, pero muy adictivo.', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', 'Uno de los primeros juegos de carreras de Nintendo.\n\nControlas una moto de motocross en pistas llenas de saltos, obstáculos y rampas.\n\nEs simple, pero muy adictivo.', NULL, 0),
(123, 'The Aventure of Link edicion Gris', 25, '735c875a3f3213e639baa8751cdb3748', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 100000, 1987, 'Acción-Aventura', 'Nintendo EAD', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', 'The Adventure of Link es la secuela directa de The Legend of Zelda y uno de los juegos más distintos dentro de la saga The Legend of Zelda.\n\nA diferencia del primer juego, combina exploración en mapa con combates en vista lateral tipo plataformas. Controlas a Link, quien debe despertar a la princesa Zelda reuniendo cristales en templos mientras gana experiencia, sube de nivel y mejora sus habilidades.\n\nEs conocido por su alta dificultad, sistema de niveles tipo RPG y combates técnicos, lo que lo hace único dentro de la franquicia.', 4, 0),
