(140, 'The Simpsond Bart vs. the Space Mutants', 25, 'f2a88380fb8d7d7de087bcef5a751fa5', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 1, 1, 30000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(141, 'Zelda II: The Adventure of Link - Classic Series', 25, '38f478deb629ed2bab082f6a8fe007ce', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 100000, 1987, 'Aventura', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', 'Zelda II: The Adventure of Link es la secuela de The Legend of Zelda dentro de la saga The Legend of Zelda.\n\nControlas a Link en una aventura para despertar a la princesa Zelda reuniendo cristales en distintos templos.\n\nA diferencia de otros juegos de la saga, combina exploración en mapa con acción en vista lateral, además de incluir elementos RPG como experiencia, niveles y mejora de habilidades.\n\nEs conocido por su alta dificultad, combates más técnicos y por ser uno de los Zelda más únicos en cuanto a jugabilidad.', 4, 0),
(142, 'Teenage Mutant Ninja Turtles', 25, '0cebdf2702db99522c5ee9121822961f', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 100000, 1989, 'Acción-Aventura', 'Konami', 'Konami', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(143, 'Tetris', 25, '439d62f1ae1a559c207fa7906df7c06c', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 40000, 1989, 'Puzzle', 'Nintendo R&D1', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
