(151, 'Kid Icarus', 25, 'c94cbad4632b0f530122f099a0a562a0', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 35000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(152, 'Urban Champion', 25, 'a7461d8b8e21da16f03e34a02a2f3dfb', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 30000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(153, 'Donkey Kong 3', 25, '97bf085aad6e68cf2453913cd4ed73be', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 25000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(154, 'Donkey Kong', 25, '7790d1894b4346570d7d623f2fbffe77', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 0, 50000, 1986, 'Plataformas', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', 'El juego presenta a Mario (llamado originalmente Jumpman) intentando rescatar a Pauline, que fue secuestrada por Donkey Kong.\n\nDebes subir por plataformas evitando barriles, fuego y otros obstáculos hasta llegar a la cima.', NULL, 0),
(155, 'Mike Tysons Punch Out', 25, '58ca7e6302f1c356be6d06b09fbf55b7', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 50000, 1987, 'Deportes', 'Nintendo R&D3', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(156, 'BattleToads', 25, '377fcdeac8975896351e688a98bd295f', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 0, 43000, 1991, 'Beat \'em up', 'Rare', 'Tradewest', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(157, 'Adventures of Lolo', 25, 'fc76981d998f51e374ad0dda000173e1', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 15000, 1989, 'Puzzle', 'HAL Laboratory', 'Nintendo', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(158, 'NES OPEN', 25, 'd58242de9c916a30560c0f814c31b39e', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 1, 1, 30000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(159, 'Balloon Fight', 25, 'b59413fad904748e9e6ec050f86ac4f5', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 35000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(160, 'Metroid', 25, '15796fb803967a28b9efee581640fd2f', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 40000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(161, 'Every n8', 25, '71bb1c1acbe3640345b70e416ebb4c8e', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 45000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(162, 'Famicom every', 25, '0a7a49a3f144518c553b088ea566ef95', 'NTSC-U', 'Fisico', 'Usado - Excelene', 1, 0, 0, 40000, 0, '', '', '', NULL, NULL, '2026-01-11 00:50:10', NULL, NULL, 0),
(163, 'Sunset Riders', 24, 'cabea9af4378567322f1f5955eeeacc5', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 0, 120000, 1993, 'Shooter', 'Konami', 'Konami', NULL, NULL, '2026-01-11 00:52:12', 'Sunset Riders es un juego estilo arcade ambientado en el viejo oeste, donde controlas a cazarrecompensas que persiguen criminales por dinero.\n\nEn la versión de SNES puedes jugar con personajes como Steve y Billy Cool, enfrentando oleadas de enemigos mientras avanzas disparando en niveles llenos de acción.\n\nAunque es una adaptación del arcade, esta versión tiene algunas diferencias: menos jugadores simultáneos y cambios en niveles y jefes, pero mantiene la esencia divertida, música icónica y dificultad desafiante.\n\nEs considerado un clásico del género “run and gun” y muy popular entre fans de los juegos retro.', 5, 1),
(164, 'Super Game Boy', 24, '0b89fc68ffb81f37b52fce3761e79a1b', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 1, 1, 75000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(165, 'Super Mario World', 24, 'fc2482f019cbc62d05c3467d69dab67b', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 0, 0, 25000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(166, 'Teenage Mutant Ninja Turtles: Turtles in Time', 24, '463281911db6fb1ba2d29af83f8f6f56', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 75000, 1992, 'Beat \'em up', 'Konami', 'Konami', NULL, NULL, '2026-01-11 00:52:12', 'El juego sigue a los cuatro hermanos tortugas, Leonardo, Donatello, Raphael y Michelangelo, mientras intentan rescatar a su sensei y padre, Splinter, de las garras del malvado Shredder y su clan de ninjas, los Foot Clan. El juego cuenta con una variedad de niveles y enemigos, desde las calles de Nueva York hasta las cuevas subterráneas y los edificios de la ciudad.', 4, 0),
(167, 'Super Ghost n Ghouls', 24, '096f19441759ce989e3c872ccabe9bda', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 115000, 1991, 'Plataformas', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(168, 'Super Street Fighter 2', 24, 'e80b2e2c7b24f7693b5e21f197eea009', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 1, 85000, 1993, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Super Street Fighter 2 es un juego de lucha que presenta a 8 personajes nuevos en comparación con el original Street Fighter 2, lo que eleva el total a 16 personajes jugables. El juego sigue la historia de Ryu y Ken, dos amigos y rivales que se enfrentan a otros luchadores de todo el mundo en un torneo de artes marciales.', 5, 0),
(169, 'Megaman X3', 24, 'b1dc7119df20b47b371bffa3a8dd7887', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 250000, 1995, 'Plataformas', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(170, 'Captain Commando', 24, '104b54d70de350b56c7b2cca21665b0d', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 0, 0, 100000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(171, 'Mega man X2', 24, '6cb8f9bf0c8e39b75b7e6cbb984c31fb', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 320000, 1994, 'Plataformas', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Mega Man X2 continúa la historia de X tras los eventos de Mega Man X.\n\nEn esta entrega, X debe enfrentarse a un nuevo grupo de enemigos mientras intenta rescatar a Zero, quien ha sido destruido y dividido en partes por los villanos.\n\nIntroduce mejoras en la jugabilidad como el “air dash”, nuevas armaduras y la posibilidad de enfrentarte a los X-Hunters, lo que añade rutas alternativas y secretos importantes.\n\nMantiene el excelente diseño de niveles, música y acción rápida de la saga Mega Man X, siendo considerado uno de los mejores juegos del SNES.', 5, 0),
(172, 'Mortal Kombat', 24, '78240cee779a8887592ae9bd58efacf7', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 70000, 1992, 'Lucha', 'Sculptured Software', 'Midway', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(173, 'Final Fight 3', 24, 'bb9a5229f2542ff67404a6853cc11a5c', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 350000, 1995, 'Beat \'em up', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Final Fight 3 es la tercera entrega de la saga Final Fight en SNES y la más completa de la trilogía en esta consola.\n\nRegresan personajes como Mike Haggar y Guy, junto a nuevos luchadores como Dean y Lucia.\n\nEl juego mejora notablemente la jugabilidad con nuevos movimientos como correr, esquivar, combos más complejos y ataques especiales. Además, presenta rutas alternativas en los niveles y múltiples finales, lo que aumenta la rejugabilidad.\n\nEs ampliamente considerado uno de los mejores beat ‘em up de la consola, gracias a su profundidad y mejoras respecto a sus predecesores.', 5, 0),
(174, 'Mortal Kombat 3', 24, '90aec2d115d34b6c95111b8bf3ca37b7', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 100000, 1995, 'Lucha', 'Midway Games', 'Williams', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(175, 'Super Mario Kart', 24, 'd5592bdb67d97807f90f335b2ec2d371', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 1, 1, 12000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(176, 'Super Mario All Stars', 24, '651c45be104b472cfeb9c77093949d85', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 110000, 1993, 'Plataformas', 'Nintendo EAD', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', '', 0, 0),
(177, 'Super Mario All Stars + Super Mario World', 24, 'b8468a2b1830f55ac6aacd2bc63ebaf1', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 45000, 1993, 'Plataformas', 'Nintendo EAD', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(178, 'Kirby Dream Course', 24, '352ff6559b2663b38dc5779d34577203', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 0, 1, 80000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(179, 'Earthbound', 24, '5f78c9905b92891e7b3f1c261d35794e', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 350000, 1994, 'Rol (RPG)', 'Ape/HAL Laboratory', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 1),
(180, 'International Superstar Soccer', 24, '0a71b81b807a943a22436ce849e51372', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 1, 250000, 1994, 'Deportes', 'Konami', 'Konami', NULL, NULL, '2026-01-11 00:52:12', 'International Superstar Soccer es uno de los juegos de fútbol más importantes de la era de 16 bits y el inicio de una saga muy reconocida de Konami.\n\nDestaca por su jugabilidad fluida, controles precisos y un enfoque más realista en comparación con otros juegos de la época. Incluye selecciones nacionales (con nombres ficticios) y diferentes modos de juego como partidos amistosos y torneos.\n\nFue muy innovador por sus animaciones, inteligencia artificial y presentación, sentando las bases de lo que más adelante evolucionaría en sagas como Pro Evolution Soccer.\n\nEs un clásico absoluto del SNES, muy recordado por su diversión en multijugador.', 5, 0),
(181, 'Zombies Ate my Neighboard', 24, 'd8e381f9282080694f5b9de58299bf90', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 45000, 1993, 'Shooter', 'LucasArts', 'Konami', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(182, 'The Legend of Zelda: A Link to the Past', 24, 'daf9106bad06a20d7a20b2bff5bbea98', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 220000, 1991, 'Aventura', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', 'The Legend of Zelda: A Link to the Past es uno de los títulos más influyentes de la saga The Legend of Zelda.\n\nControlas a Link en una misión para rescatar a la princesa Zelda y derrotar al villano Ganon.\n\nEl juego introduce el concepto de dos mundos paralelos: el Light World y el Dark World, lo que permite resolver puzzles y avanzar en la historia de forma innovadora. También incluye una gran variedad de ítems, mazmorras y secretos.\n\nDestaca por su diseño de niveles, música, exploración y equilibrio perfecto entre acción y puzzles, estableciendo la fórmula que seguirían muchos juegos posteriores de la saga.', 5, 0),
(183, 'Megaman X', 24, '5810be12b2e352d5535b8ea5040b7efb', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 1, 150000, 1993, 'Acción', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Mega Man X es una evolución de la saga clásica de Mega Man, introduciendo un tono más serio y mecánicas más avanzadas.\n\nControlas a X, un robot avanzado que lucha contra otros “Reploids” rebeldes liderados por Sigma. El juego mantiene la estructura de elegir niveles libremente, cada uno con un jefe que otorga nuevas habilidades al derrotarlo.\n\nIntroduce mejoras clave como dash, trepar paredes y armaduras ocultas que aumentan las habilidades del personaje, lo que le da más profundidad y velocidad a la jugabilidad.\n\nEs famoso por su excelente diseño de niveles, música icónica y dificultad equilibrada, siendo un clásico imprescindible del SNES.', 5, 0),
(184, 'Donkey Kong Country 2: Diddy\'s Kong Ques', 24, '05df4e3280de41820a14b8780969847d', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 135000, 1995, 'Plataformas', 'Rare', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(185, 'Aladdin', 24, '4469a783d99b1d731368406c423c4555', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 1, 1, 60000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(186, 'Street Fighter 2', 24, '121ffd008a4bcf3117955fc310b6f7c5', 'NTSC-U', 'Fisico', 'Usado - Excelen', 1, 1, 1, 75000, 0, '', '', '', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(187, 'Street Fighter 2 Turbo', 24, '8c5242f1b845512055f5e7133f5dd623', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 100000, 1993, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(188, 'Street Fighter Alpha 2', 24, 'e5ba6026430ae390a403d71da33a1db5', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 1, 150000, 1996, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Street Fighter Alpha 2 es una evolución directa de Street Fighter Alpha dentro de la saga Street Fighter.\n\nIntroduce mejoras importantes en la jugabilidad, como el sistema Alpha Counter (contraataques) y combates más balanceados. Mantiene los estilos de juego y añade nuevos personajes y escenarios.\n\nIncluye luchadores icónicos como Ryu, Ken Masters y Chun-Li, con movimientos refinados y mayor profundidad técnica.\n\nEs muy valorado por su equilibrio, velocidad y estilo visual, siendo un clásico competitivo dentro de los juegos de pelea.', 5, 0);
INSERT INTO `juegos` (`id`, `titulo`, `plataforma_id`, `id_imagen`, `region`, `formato`, `estado`, `cartucho`, `manual`, `caja`, `valor`, `lanzamiento`, `genero`, `desarrollador`, `publicador`, `fecha_compra`, `notas`, `created_at`, `comentario`, `puntuacion`, `favorito`) VALUES
(189, 'Super Castlevania IV', 24, 'ed1ff4985683b7704b3151948d3cc51c', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 220000, 1991, 'Plataformas', 'Konami', 'Konami', NULL, NULL, '2026-01-11 00:52:12', 'Super Castlevania IV es una reinterpretación mejorada del primer Castlevania dentro de la saga Castlevania.\n\nControlas a Simon Belmont, quien debe atravesar el castillo de Dracula enfrentando criaturas clásicas como esqueletos, fantasmas y monstruos.\n\nEl juego destaca por su gran mejora en controles: puedes usar el látigo en múltiples direcciones, girarlo para bloquear proyectiles y colgarte de él. Además, aprovecha efectos gráficos avanzados del SNES como rotaciones y escalados.\n\nEs muy recordado por su ambientación, música y jugabilidad más accesible que otros Castlevania, sin perder el desafío.', 5, 0),
(190, 'Megaman 7', 24, '6963023f204b20c56c6c0d888464c906', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 200000, 1995, 'Acción', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(191, 'Super Mario World 2: Yoshi\'s Island', 24, '7d338f35954d5c391824cbe4d963e7ef', 'NTSC-U', NULL, 'Usado - Bueno', 1, 1, 1, 150000, 1995, 'Plataformas', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', 'Yoshi’s Island (oficialmente Super Mario World 2: Yoshi\'s Island) es un spin-off de la saga Super Mario.\n\nEn el juego controlas a Yoshi, quien debe proteger y llevar al bebé Mario a través de distintos niveles para reunirlo con su hermano Luigi.\n\nDestaca por su estilo gráfico único tipo dibujo a mano, mecánicas innovadoras como lanzar huevos y su sistema donde debes rescatar a Baby Mario cuando cae de Yoshi. Además, ofrece niveles creativos, secretos y una jugabilidad muy pulida.\n\nEs famoso por su diseño artístico, música y por innovar dentro del género de plataformas en la era de SNES.', 5, 0),
(192, 'Chrono Trigger', 24, 'bf56b60ff52faeebdae0dc7707a76459', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 0, 260000, 1995, 'Rol (RPG)', 'Square', 'Square', NULL, NULL, '2026-01-11 00:52:12', NULL, NULL, 0),
(193, 'Super Mario RPG: Legend of the Seven Stars', 24, 'be46435f317b4b293804d5d80a3260f7', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 0, 100000, 1996, 'Rol (RPG)', 'Square', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', 'Super Mario RPG es un juego que mezcla el mundo de Super Mario con mecánicas de rol desarrolladas por Square.\n\nLa historia comienza cuando Bowser secuestra a la princesa, pero una nueva amenaza aparece: Smithy, quien destruye la Star Road. Entonces, Mario forma equipo con aliados inesperados, incluyendo a Bowser y nuevos personajes como Mallow y Geno.\n\nEl juego destaca por su sistema de combate por turnos con timing activo (puedes mejorar ataques presionando botones en el momento justo), humor, historia entretenida y gráficos isométricos innovadores para la época.\n\nEs considerado un clásico que dio origen a futuras sagas como Paper Mario y Mario & Luigi.', 5, 0),
(194, 'Super Metroid', 24, '9cecd11fee833db539f7d67ad4218c4b', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 1, 120000, 1994, 'Acción-Aventura', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', 'Super Metroid es una de las entregas más importantes de la saga Metroid.\n\nControlas a Samus Aran, quien viaja al planeta Zebes para recuperar un Metroid robado por Ridley.\n\nEl juego destaca por su exploración no lineal, donde obtienes habilidades que te permiten acceder a nuevas áreas, creando una experiencia de progreso abierta. Tiene una atmósfera única, con poca narrativa directa y mucho storytelling ambiental.\n\nEs famoso por su diseño de mapa, música, ambientación y por definir el género “Metroidvania”, influyendo en muchos juegos posteriores.', 5, 0),
(195, 'X-Men: Mutant Apocalypse', 24, '8359db79bd1cf8a6a7f0a58724b75924', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 50000, 1994, 'Plataformas', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'X-Men: Mutant Apocalypse es un juego de acción basado en los cómics de los X-Men.\n\nPuedes jugar con distintos personajes como Wolverine, Cyclops, Beast, Gambit y Psylocke, cada uno con habilidades únicas y niveles propios.\n\nEl juego combina plataformas con combate, y luego reúne a los personajes para enfrentar a villanos como Apocalypse.\n\nDestaca por sus gráficos coloridos, animaciones fluidas y fidelidad al estilo de los cómics. Es uno de los mejores juegos de superhéroes en SNES, aunque su dificultad puede ser exigente.', 4, 0),
(196, 'Super Punch Out', 24, 'd338e2fbe49a0859bb20216688d3fcbc', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 150000, 1994, 'Deportes', 'Nintendo', 'Nintendo', NULL, NULL, '2026-01-11 00:52:12', 'Super Punch-Out!! es la secuela del clásico de boxeo de Nintendo, donde controlas a Little Mac (aunque en esta versión no se le nombra directamente).\n\nEl juego se basa en combates uno contra uno contra una galería de oponentes únicos, cada uno con patrones y debilidades específicas que debes aprender para ganar.\n\nDestaca por su estilo caricaturesco, animaciones fluidas y jugabilidad basada en reflejos y memorización. A diferencia de versiones anteriores, elimina algunos elementos como el sistema de estrellas, enfocándose más en la precisión y timing.\n\nEs considerado uno de los mejores juegos de boxeo arcade y un clásico muy entretenido por su diseño de enemigos y desafío progresivo.', 5, 0),
(197, 'Final Fight', 24, '0f36d52157057c6cd8a1b9fc43b1887a', 'NTSC-U', NULL, 'Usado - Bueno', 1, 0, 1, 60000, 1989, 'Beat \'em up', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Final Fight es uno de los beat ‘em up más influyentes de la historia. La historia sigue a Mike Haggar, exluchador y alcalde de Metro City, junto a Cody Travers y Guy, quienes luchan contra la banda Mad Gear para rescatar a Jessica.\n\nEl juego consiste en avanzar por calles derrotando enemigos con golpes, agarres y armas improvisadas. Destaca por su jugabilidad cooperativa en arcade, personajes carismáticos y dificultad desafiante.\n\nLa versión de SNES fue muy popular, aunque tenía recortes (menos personajes y sin modo cooperativo), mientras que la versión arcade es considerada la experiencia definitiva.', 5, 0),
(198, 'Final Fight 2', 24, 'f4c9c3edf9a05f82f9108cbb1884e921', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 150000, 1993, 'Beat \'em up', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 00:52:12', 'Final Fight 2 es la secuela directa de Final Fight, desarrollada exclusivamente para SNES.\n\nEn esta entrega, Mike Haggar regresa junto a nuevos personajes como Maki Genryusai y Carlos Miyamoto para rescatar a la familia de Guy, enfrentándose nuevamente a la organización criminal Mad Gear.\n\nA diferencia del primer juego en SNES, esta versión sí incluye modo cooperativo para dos jugadores, más escenarios (ambientados en distintas partes del mundo) y una jugabilidad más fluida.\n\nAunque no alcanza el nivel del arcade original, es uno de los beat ‘em up más sólidos en la consola.', 4, 0),
