(298, 'Tatsunoko vs Capcom', 32, '041671b8928543541c220b2c6b3bbf9b', '', '', '', 1, 1, 1, 85000, 0, '', '', '', NULL, NULL, '2026-01-11 03:04:44', NULL, NULL, 0),
(299, 'Nintendo World Championship Nes Edition', 26, '295479fdb55be87f2b8e27c97e783cea', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 50000, 2024, 'Party', 'Nintendo EPD', 'Nintendo', NULL, NULL, '2026-01-11 03:04:44', 'Nintendo World Championships: NES Edition es un juego inspirado en las competencias oficiales de Nintendo de los años 90.\n\nEn lugar de jugar los juegos completos, enfrentas más de 150 desafíos cortos tipo speedrun basados en clásicos de NES como:\n\nSuper Mario Bros.\nThe Legend of Zelda\nMetroid\n\nCada desafío consiste en completar una tarea lo más rápido posible (por ejemplo: terminar una parte de un nivel o conseguir un ítem).', 4, 0),
(300, 'Grand Theft Auto: The Trilogy – The Definitive Edition', 38, '70c8bd1246a1b30a88578aefed7ee915', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2023, 'Mundo Abierto', 'Grove Street Games', 'Rockstar Games', NULL, NULL, '2026-01-11 03:08:30', NULL, NULL, 0),
(301, 'Horizon Zero Dawn', 38, 'ce6ae25a63600b14d6da2015a3a8926b', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 10000, 2017, 'Aventura', 'Guerrilla Games', 'Sony Interactive Entertainment', NULL, NULL, '2026-01-11 03:08:30', NULL, NULL, 0),
(302, 'Soulcalibur VI', 38, '9270d13dd501c7ac1104ffac0aa1ff5b', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 10000, 2018, 'Lucha', 'Dimps de Bandai Namco Studios', 'Entretenimiento de Bandai Namco', NULL, NULL, '2026-01-11 03:08:30', 'SoulCalibur VI es una especie de reinicio de la historia dentro de la saga Soulcalibur, reimaginando los eventos del primer juego.\n\nDestaca por su sistema de combate basado en armas blancas, donde cada personaje tiene un estilo único. Introduce mecánicas como el “Reversal Edge”, que agrega enfrentamientos tipo “piedra, papel o tijera” dentro del combate.\n\nIncluye personajes clásicos como Mitsurugi y Sophitia, además de invitados especiales como Geralt of Rivia.\n\nTambién destaca por su modo creación de personajes muy completo y su equilibrio entre accesibilidad y profundidad competitiva.', 5, 0),
(303, 'Tekken 7', 38, '4e6e3f3bc62788d64526657406e8b6ff', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 10000, 2015, 'Lucha', 'Bandai Namco Entertainment', 'Bandai Namco Entertainment', NULL, NULL, '2026-01-11 03:08:30', 'Tekken 7 es la séptima entrega principal de la saga Tekken y cierra la historia del conflicto entre Heihachi Mishima y Kazuya Mishima.\n\nIntroduce mecánicas como el “Rage System”, que permite realizar ataques especiales cuando tienes poca vida, agregando tensión y estrategia a los combates. Mantiene el clásico sistema de lucha 3D con combos, juggles y gran profundidad técnica.\n\nEl juego cuenta con una amplia variedad de personajes clásicos y nuevos, además de invitados de otras franquicias. Es uno de los títulos más importantes en torneos de fighting, incluyendo eventos como EVO Championship Series.', 5, 0),
(304, 'Street Fighter V - Champion Edition', 38, '62a0f90eb92bc2bd6f65bba764a0276b', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 20000, 2020, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-01-11 03:08:30', NULL, NULL, 0),
