(383, 'Marvel vs. Capcom 2: New Age of Heroes', 27, '5d00d55ef1bbb185d8d90381f93a7dac', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2000, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-02-23 02:05:37', NULL, NULL, 0),
(384, 'Capcom vs. SNK', 27, 'd44b82b7853f9e664636a694446d6376', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2000, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-02-23 02:08:56', NULL, NULL, 0),
(385, 'Capcom vs. SNK 2: Mark of the Millennium 2001', 27, '1b3949235e15f95f35f4073b69bfd26a', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 40000, 2001, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-02-23 02:11:57', 'Capcom vs. SNK 2 es un crossover legendario que reúne personajes de las sagas de Capcom y SNK, como Ryu, Kyo Kusanagi y Terry Bogard.\n\nSu mayor innovación es el sistema “Groove”, que permite elegir distintos estilos de juego basados en mecánicas de sagas como Street Fighter Alpha o The King of Fighters, cambiando completamente la forma de pelear.\n\nTambién incluye el sistema Ratio, donde puedes formar equipos balanceando la fuerza de los personajes. Con una enorme plantilla de luchadores, gran profundidad técnica y balance competitivo, es un clásico tanto en arcade como en torneos.', 5, 0),
(386, 'Power Smash', 27, '5d027e73c5143172b0a707b0c8d4449f', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 1999, 'Deportes', 'Power Smash', 'Sega', NULL, NULL, '2026-02-23 02:22:39', NULL, NULL, 0),
