(393, 'Metal Gear Solid: Peace Walker', 49, 'ef65abc1aec489423b72765d18557acb', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 60000, 2010, 'Acción', 'Kojima Productions', 'Konami', NULL, NULL, '2026-02-25 01:22:53', NULL, NULL, 1),
(394, 'Mario Kart DS', 40, '7fa87ceca3d86c593e20cc5d96deb4b6', 'NTSC-U', NULL, 'Usado - Bueno', 1, 1, 1, 20000, 2005, 'Carreras', 'Mario Kart DS', 'Nintendo', NULL, NULL, '2026-03-20 18:54:26', '', NULL, 0),
(395, 'Metroid Pinball', 40, '0944aaceeead31dbe6671a64dc5253a0', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 55000, 2005, 'Puzzle', 'Metroid Pinball', 'Fuse Games', NULL, NULL, '2026-03-20 18:57:31', 'Una mezcla entre pinball (máquinas de bolitas) y el universo de Metroid Prime.\n\nControlas a Samus Aran en forma de Morph Ball, rebotando como una bola dentro de mesas llenas de enemigos y misiones', NULL, 0),
(396, 'Rabbids Go Home A Comedy Adventure', 40, '8d4f4967307efd181df31cc842f267b2', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 10000, 2009, 'Acción-Aventura', 'Ubisoft', 'Ubisoft', NULL, NULL, '2026-03-20 18:59:39', 'Los Rabbids quieren ir a la Luna…\npero creen que pueden llegar haciendo una montaña gigante de basura 🤣\n\nAsí que recorren la ciudad robando TODO lo que encuentran para construir su torre.', NULL, 0),
(397, 'Mario Kart DS', 40, 'e6bafa38f285e46bb834eed1d63de12c', 'NTSC-U', NULL, 'Usado - Excelente', 0, 1, 1, 5000, 2005, 'Carreras', 'Nintendo', 'Nintendo', NULL, NULL, '2026-03-20 19:14:11', 'Uno de los mejores juegos de la saga Mario Kart y el primero con juego online gracias a Nintendo Wi-Fi Connection.\n\nRápido, técnico y muy competitivo.', NULL, 0);
INSERT INTO `juegos` (`id`, `titulo`, `plataforma_id`, `id_imagen`, `region`, `formato`, `estado`, `cartucho`, `manual`, `caja`, `valor`, `lanzamiento`, `genero`, `desarrollador`, `publicador`, `fecha_compra`, `notas`, `created_at`, `comentario`, `puntuacion`, `favorito`) VALUES
(398, 'Mario Kart DS', 40, 'eca0d9bd878ce8c13dec1a1c9baca030', 'NTSC-U', NULL, 'Usado - Excelente', 0, 1, 1, 5000, 2005, 'Carreras', 'Nintendo', 'Nintendo', NULL, NULL, '2026-03-20 19:15:30', 'Uno de los mejores juegos de la saga Mario Kart y el primero con juego online gracias a Nintendo Wi-Fi Connection.\n\nRápido, técnico y muy competitivo.', NULL, 0),
(399, 'Call of Duty: Modern Warfare 3', 40, '4874a98bdb03415ddd634d2fe5769fe7', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 15000, 2011, 'FPS', 'Call of Duty: Modern Warfare 3', 'Activition', NULL, NULL, '2026-03-20 19:19:23', 'Una versión exclusiva de Nintendo DS basada en Call of Duty: Modern Warfare 3.\n\n👉 Importante:\nNo es un port directo del juego de PS3/Xbox 360, sino una historia paralela adaptada al hardware portátil.', NULL, 0),
(400, 'Transformers War For Cybertron Decepticons', 40, '4cdd3ab06e9a9e16fcec2100fb4832e0', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 25000, 2010, 'Acción', 'Vicarious Visions', 'Activition', NULL, NULL, '2026-03-21 01:51:19', 'Un juego de acción basado en el universo de Transformers, centrado en el lado de los Decepticons.\n\n👉 Es una versión diferente al juego de consolas (PS3/Xbox 360), con su propia historia y estilo.\n\nTambién existe la versión Autobots, con campaña distinta.', NULL, 0),
(401, 'GoldenEye 007', 40, 'be84562a16907747dacd0790255eaf46', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 25000, 2010, 'FPS', 'GoldenEye 007', 'Activision', NULL, NULL, '2026-03-21 01:53:09', 'Una versión portátil del juego GoldenEye 007, basada en la reinterpretación moderna de la película.\n\n👉 Importante:\nNo es el clásico de Nintendo 64, sino una versión adaptada al estilo de los juegos modernos de James Bond.', NULL, 0),
(402, 'God of War Chains of Olympus', 49, '37e1018af9f60c7f396911d858123aa8', 'PAL', NULL, 'Nuevo', 1, 1, 1, 30000, 2008, 'Hack and Slash', 'Ready at Dawn', 'Sony', NULL, NULL, '2026-03-21 02:01:25', 'Una precuela de la saga God of War.\n\nCuenta una historia anterior a los eventos del primer juego, mostrando a Kratos sirviendo a los dioses del Olimpo.\n\nEs considerado uno de los mejores juegos de PSP.', NULL, 0),
(403, 'Donkey Kong DK: Jungle Climber', 40, 'd34a8b8241a1b4d848d7c7366f4bc8fe', 'NTSC-U', NULL, 'Usado - Bueno', 0, 1, 1, 20000, 2007, 'Plataformas', 'Paon', 'Nintendo', NULL, NULL, '2026-03-21 18:49:36', 'Secuela espiritual de Donkey Kong: King of Swing (GBA).\n\nUn juego único donde controlas a Donkey Kong trepando usando las manos, en lugar de correr como en los plataformas tradicionales.', NULL, 0),
(404, 'The Legend of Zelda: Phantom Hourglass', 40, '209b1723b17a774c4792b65b680e77b4', 'NTSC-U', NULL, 'Usado - Excelente', 0, 1, 1, 20000, 2007, 'Acción-Aventura', 'Nintendo', 'Nintendo', NULL, NULL, '2026-03-21 18:51:16', 'Secuela directa de The Legend of Zelda: The Wind Waker.\n\nSigue las aventuras de Link y Tetra en el mar, con un enfoque innovador usando completamente la pantalla táctil del Nintendo DS.', 4, 0),
(405, 'Brain Age 2: More Training in Minutes a Day', 40, '75768a09d51e18e87865b5a58553ed5e', 'NTSC-U', NULL, 'Usado - Bueno', 0, 1, 1, 10000, 2007, 'Puzzle', 'Nintendo', 'Nintendo', NULL, NULL, '2026-03-21 18:53:39', 'La secuela de Brain Age, basada en los estudios del neurólogo japonés Ryuta Kawashima.\n\nEl objetivo es entrenar tu cerebro diariamente con ejercicios rápidos.', NULL, 0),
(406, 'Mortal Kombat: Unchained', 49, '36da13e496b4f40f66dc7ddf785e4e4b', '', NULL, 'Usado - Excelente', 1, 1, 1, 40000, 2006, 'Lucha', 'Midway', 'Midway', NULL, NULL, '2026-03-21 18:55:46', 'Una versión mejorada portátil de Mortal Kombat: Deception, adaptada para PSP.\n\nIncluye más contenido, personajes extra y modos adicionales.', NULL, 0),
(407, 'Midway Arcade Treasures: Extended Play', 49, '9e2f03113f19b2a17943f0191d1cdf77', 'PAL', NULL, 'Usado - Excelente', 0, 1, 0, 20000, 2005, 'Arcade', 'Midway', 'Midway', NULL, NULL, '2026-03-21 18:57:36', 'Una colección portátil de clásicos arcade de Midway, similar a las versiones de consola, pero adaptada para PSP.\n\nIncluye juegos icónicos de los años 80 y 90.\n\n🎮 Juegos incluidos (destacados)\n🥊 Peleas\nMortal Kombat\nMortal Kombat II\nMortal Kombat 3\n🦍 Acción\nRampage\nRampage World Tour\nNARC\nSmash TV\n🔫 Shooter\nTotal Carnage\n🏎️ Carreras\nSpy Hunter\n\n(La lista completa incluye más de 20 juegos.)\n\n🕹️ Características\nEmulación de arcade.\nGuardado de progreso.\nAjustes de dificultad.\nMultijugador local (en algunos juegos).', 4, 0),
(408, 'Virtua Tennis World Tour', 49, 'd22956c5b618bf6bc9bd1db6adc76d3a', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 10000, 2005, 'Deportes', 'Sega', 'Sega', NULL, NULL, '2026-03-21 19:02:38', 'La versión portátil de la famosa saga Virtua Tennis (conocida como Power Smash en Japón).\n\nMantiene la jugabilidad arcade rápida y accesible, adaptada perfectamente a PSP.', NULL, 0),
(409, 'SpongeBob vs. The Big One: Beach Party Cook-Off', 40, 'd1828936b97fadf87480b437cb249c2e', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 30000, 2009, 'Simulación', 'Playlogic', 'THQ', NULL, NULL, '2026-03-21 19:07:21', 'Un juego de Bob Esponja basado en cocina, donde participas en competencias para preparar comida en una fiesta playera.\n\nInspirado en el especial de la serie “SpongeBob vs. The Big One”.', NULL, 0),
(410, 'The King of Fighters \'94', 51, '516c9d3d56be7082bbdc32e55cc1159d', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 1994, 'Lucha', 'SNK', 'SNK', NULL, NULL, '2026-03-21 19:12:57', 'El primer juego de la legendaria saga The King of Fighters.\n\nIntroduce el concepto de equipos de 3 luchadores, mezclando personajes de distintas franquicias de SNK.', 4, 0),
(411, 'LittleBigPlanet', 49, '834a90c472d32390130900ac79b0b92c', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2009, 'Acción-Aventura', 'LittleBigPlanet', 'Play Station', NULL, NULL, '2026-03-25 19:07:53', 'La versión portátil del famoso LittleBigPlanet.\n\nUn juego donde no solo juegas niveles…\n👉 también puedes crear tus propios niveles 🎮✨', NULL, 0),
(412, 'LittleBigPlanet', 49, 'd4a2bde9529af82a8ff53411d0af5088', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2009, 'Acción-Aventura', 'LittleBigPlanet', 'Play Station', NULL, NULL, '2026-03-25 19:09:41', 'La versión portátil del famoso LittleBigPlanet.\n\nUn juego donde no solo juegas niveles…\n👉 también puedes crear tus propios niveles 🎮✨', NULL, 0),
(413, 'ModNation Racers', 49, '5d4b5f988d119e6d8afcaae51cea4755', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 20000, 2010, 'Carreras', 'SCE San Diego Studio', 'Sony', NULL, NULL, '2026-03-25 19:13:17', 'Un juego de carreras estilo Mario Kart, pero con un fuerte enfoque en crear y personalizar todo.\n\nForma parte de la filosofía de Sony tipo “Play, Create, Share” (jugar, crear y compartir).', NULL, 0),
(414, 'Gran Turismo', 49, '249aa0b470529b1ca311029de1a63372', 'PAL', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2009, 'Carreras', 'Gran Turismo', 'Sony Interactive Entertainment', NULL, NULL, '2026-03-25 19:16:58', 'La versión portátil de la famosa saga Gran Turismo, enfocada en ofrecer una experiencia de conducción realista en PSP.', 4, 0),
(415, 'Gran Turismo', 49, '68fdbbba968fd5cfa38bea25ee54e3ba', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2009, 'Carreras', 'Gran Turismo', 'Sony Interactive Entertainment', NULL, NULL, '2026-03-25 19:18:47', 'La versión portátil de la famosa saga Gran Turismo, enfocada en ofrecer una experiencia de conducción realista en PSP.', 4, 0),
(416, 'Final Fantasy VII', 47, '2f0ecb940aeece9793628e1d356dc5b6', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 50000, 1997, 'Rol (RPG)', 'Square', 'Square', NULL, NULL, '2026-03-26 00:42:01', 'Sigues la historia de Cloud Strife, un mercenario que se une al grupo rebelde AVALANCHE para luchar contra la corporación Shinra, que explota la energía del planeta.\n\nPero la historia crece hasta enfrentar una amenaza mayor: Sephiroth.\n\n👉 Es uno de los RPG más importantes de la historia.', 5, 0),
(417, 'Jak and Daxter: The Lost Frontier', 49, 'f85a770d9a1fbfb3067ff21c47693631', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2009, 'Acción-Aventura', 'High Impact Games', 'Sony Computer Entertainment', NULL, NULL, '2026-03-26 00:47:17', 'Jak and Daxter: The Lost Frontier es un juego de acción y aventura que sigue las historias de Jak y su fiel amigo Daxter en una nueva aventura. La historia se desarrolla después de los eventos de Jak 3, donde Jak y Daxter se ven obligados a abandonar su hogar en busca de una nueva fuente de energía para su planeta, que está muriendo.', NULL, 0),
(418, 'Need for Speed: Most Wanted', 49, 'b58ea66d21a2c79432abf3216be413cc', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 35000, 2005, 'Carreras', 'EA Black Box', 'Electronic Arts', NULL, NULL, '2026-03-26 00:49:16', 'Need for Speed: Most Wanted es un juego de carreras de alta velocidad que se desarrolla en un mundo abierto, donde el jugador asume el papel de un conductor que debe evadir a la policía y competir con otros conductores para convertirse en el más buscado.', 4, 0),
(419, 'Tomb Raider: Anniversary', 49, '66e6cd1f3ee93d5d8fa9c773358042c6', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 50000, 2007, 'Acción-Aventura', 'Crystal Dynamics', 'Eidos Interactive', NULL, NULL, '2026-03-26 00:51:25', 'Tomb Raider: Anniversary es un juego de acción y aventura que sigue a la protagonista Lara Croft en una búsqueda por encontrar la legendaria Atlántida. El juego es una reimaginación del clásico Tomb Raider, con gráficos y jugabilidad actualizados.', 4, 0),
(420, 'SOCOM: US Navy Seals Fireteam Bravo 2', 49, '9af35750886025df21f6831e2fc9c730', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 1000, 2006, 'Acción', 'Zipper Interactive', 'Sony Computer Entertainment', NULL, NULL, '2026-03-30 23:02:47', 'SOCOM: US Navy Seals Fireteam Bravo 2 es un juego de acción táctica desarrollado por Zipper Interactive y publicado por Sony Computer Entertainment. Lanzado en 2006 para la consola PlayStation Portable, el juego sigue la historia de un equipo de SEAL de la Marina de los Estados Unidos mientras realizan misiones de combate en diferentes partes del mundo.', 4, 0),
(421, 'Tekken: Dark Resurrection', 49, '52a6dfffedb7e5a7be8cf2248768ff80', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 2006, 'Lucha', 'Namco', 'Namco Bandai Games', NULL, NULL, '2026-03-30 23:07:36', 'Tekken: Dark Resurrection es una versión mejorada de Tekken 5, que trae más personajes, escenarios y ajustes en la jugabilidad. Mantiene el clásico sistema de combate 3D de la saga, donde eliges un luchador y compites en el torneo “King of Iron Fist”.\n\nLa versión de PSP destaca porque logra llevar una experiencia muy cercana a arcade en portátil, con gráficos fluidos, modo historia, personalización de personajes y multijugador local. Fue considerado uno de los mejores juegos de pelea en consola portátil de su época.', 5, 0),
(422, 'The 3rd Birthday', 49, 'dfc3075e5e210b7aefdf46e8e6949583', 'NTSC-J', NULL, 'Usado - Excelente', 1, 1, 1, 20000, 2010, 'Acción', 'Square Enix', 'Square Enix', NULL, NULL, '2026-03-30 23:10:00', 'The 3rd Birthday es un juego de acción que funciona como secuela de la saga Parasite Eve. Sigues a Aya Brea, quien enfrenta una amenaza misteriosa en Nueva York llamada los “Twisted”.\n\nEl juego introduce el sistema “Overdive”, que permite transferir la conciencia de Aya entre distintos soldados durante el combate, creando una mecánica estratégica única. Combina disparos en tiempo real con elementos RPG como mejoras de habilidades y armas.\n\nAunque destacó por sus gráficos y mecánicas innovadoras en PSP, la historia generó opiniones divididas entre los fans de la saga original.', 4, 0),
(423, 'Street Fighter Alpha 3 MAX', 49, '62548ffdd096ca2600eacd4808657e26', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 35000, 2006, 'Lucha', 'Capcom', 'Capcom', NULL, NULL, '2026-03-30 23:12:00', 'Street Fighter Alpha 3 MAX es la versión más completa de Street Fighter Alpha 3, incluyendo una enorme cantidad de personajes (más de 30), modos de juego y mejoras exclusivas para PSP.\n\nEl juego mantiene el sistema clásico de combate 2D de la saga Street Fighter, pero añade los estilos de lucha “ISM” (X-ISM, A-ISM y V-ISM), que cambian completamente la forma de jugar cada personaje.\n\nLa versión MAX destaca por incluir modos adicionales como World Tour, Survival y entrenamiento, además de personajes extra que no estaban en la versión arcade original. Es muy valorado por su profundidad jugable y por ofrecer una experiencia casi idéntica a arcade en una consola portátil.', 5, 0),
(424, 'Resistance: Retribution', 49, '8207dcf8a9fc5baa5faa007318ff6a8c', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 20000, 2009, 'Acción-Aventura', 'Bend Studio', 'Sony Computer Entertainment', NULL, NULL, '2026-04-09 03:58:41', 'Resistance: Retribution es un spin-off de la saga Resistance. La historia sigue a James Grayson, un soldado británico que lucha contra la invasión alienígena conocida como los Chimera en una Europa devastada.\n\nA diferencia de los juegos principales en consola, este título usa una cámara en tercera persona y un sistema de apuntado adaptado a PSP, lo que lo hace más accesible en portátil sin perder intensidad.\n\nDestaca por su narrativa, ambientación oscura y variedad de armas, además de incluir un modo especial si se conecta con Resistance 2 en PlayStation 3, desbloqueando contenido adicional.', 4, 0),
(425, 'God of War: Ghost of Sparta', 49, '811504023280ba065eb7cfe66a5c878d', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 60000, 2010, 'Acción-Aventura', 'Ready at Dawn junto a Santa Monica Studio', 'Sony Computer Entertainment', NULL, NULL, '2026-04-09 04:02:32', 'God of War: Ghost of Sparta continúa la historia de Kratos entre los eventos de God of War y God of War II.\n\nEn esta entrega, Kratos busca respuestas sobre su pasado y su familia, lo que lo lleva a enfrentarse a dioses, titanes y criaturas mitológicas. La historia profundiza en su origen, especialmente en su relación con su hermano.\n\nEl juego destaca por sus gráficos impresionantes para PSP, combates intensos, puzzles y grandes jefes, manteniendo la esencia épica de la saga God of War en formato portátil.', 5, 0),
(426, 'Final Fantasy VIII', 47, '4b5755052591094a81ce4e4d11958581', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 30000, 1999, 'Rol (RPG)', 'Square', 'Square', NULL, NULL, '2026-04-09 04:08:25', 'Final Fantasy VIII sigue la historia de Squall Leonhart, un joven estudiante militar que se ve envuelto en un conflicto global junto a su equipo.\n\nEl juego introduce sistemas únicos como el “Junction”, que permite vincular magia a las estadísticas para fortalecer personajes, y la obtención de hechizos mediante extracción en combate. También destaca por eliminar el sistema tradicional de experiencia para enemigos, permitiendo estrategias diferentes.\n\nEs recordado por su historia más madura y romántica, su estilo visual más realista y su icónica banda sonora, siendo uno de los títulos más distintivos dentro de la saga Final Fantasy.', 5, 0),
(427, 'Battle Arena Toshinden', 47, 'd5d64f61e8b6250b97c2881ad810375a', 'NTSC-U', NULL, 'Usado - Excelente', 1, 0, 0, 15000, 1995, 'Lucha', 'Tamsoft', 'Sony Computer Entertainment', NULL, NULL, '2026-04-09 04:15:26', 'Battle Arena Toshinden fue uno de los primeros juegos de pelea en 3D para la PlayStation, destacando por permitir movimiento lateral (side-step), algo poco común en ese tiempo.\n\nIncluye personajes como Eiji Shinjo, cada uno con armas y estilos de combate distintos. El juego se centra en duelos uno contra uno con ataques especiales y escenarios en 3D.\n\nAunque fue muy popular al inicio de la consola, con el tiempo fue superado por títulos más avanzados como Tekken, que ofrecían una jugabilidad más profunda y pulida.', 3, 0),
(428, 'Resident Evil 2', 38, '273e10c8af78bb3d779a479c33628de9', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 15000, 2019, 'Survival Horror', 'Capcom', 'Capcom', NULL, NULL, '2026-04-09 04:21:12', 'Resident Evil 2 (2019) es un remake del clásico Resident Evil 2. La historia sigue a Leon S. Kennedy y Claire Redfield, quienes intentan sobrevivir a un brote zombi en Raccoon City.\n\nEl juego moderniza completamente la experiencia con gráficos realistas, cámara sobre el hombro y una atmósfera mucho más inmersiva. Mantiene la esencia del original con exploración, resolución de puzzles y gestión de recursos, pero con mecánicas actuales.\n\nDestaca por su tensión constante, enemigos memorables como el Tyrant (Mr. X) y su excelente diseño de sonido y escenarios.', 5, 0),
(429, 'Vegas Stakes', 24, 'ad23b9a82aa6d315e58f51f359c5859c', 'NTSC-U', NULL, 'Nuevo', 1, 1, 1, 30000, 1993, 'Simulación', 'HAL Laboratory', 'Nintendo', NULL, NULL, '2026-04-09 18:13:37', 'Vegas Stakes es un simulador de casino donde comienzas con poco dinero y debes intentar ganar apostando en diferentes juegos de azar.\n\nIncluye póker, blackjack, ruleta y tragamonedas, recreando la experiencia de un casino. A medida que ganas dinero, puedes acceder a casinos más lujosos con apuestas más altas.\n\nAdemás, incorpora pequeños eventos y encuentros con personajes que pueden ayudarte o perjudicarte, lo que le da un toque de historia y variedad.\n\nEs un juego tranquilo y estratégico, ideal para cambiar del típico juego de acción o plataformas en SNES.', 4, 0),
(430, 'Resident Evil 3', 38, '7361c13a3106b58990f826c3d86a7c6f', 'NTSC-U', NULL, 'Usado - Excelente', 1, 1, 1, 15000, 2020, 'Survival Horror', 'Capcom', 'Capcom', NULL, NULL, '2026-04-14 00:08:54', 'Resident Evil 3 (2020) es una reinterpretación del clásico Resident Evil 3: Nemesis.\n\nSigues a Jill Valentine mientras intenta escapar de Raccoon City durante el brote zombi. A lo largo del juego es perseguida constantemente por Nemesis, una criatura imparable diseñada para eliminar a los miembros de S.T.A.R.S.\n\nEl remake moderniza la jugabilidad con gráficos actuales, acción más dinámica y narrativa más cinematográfica. Sin embargo, elimina algunas secciones del juego original, lo que lo hace más corto.\n\nAun así, destaca por su intensidad, ritmo rápido y la presión constante que genera Nemesis.', 4, 0),
(431, 'Wii Play Motion Big Box', 32, 'f01f2b0b600010a1d116d0e3ec5141a3', 'NTSC-U', NULL, 'Usado - Bueno', 1, 1, 1, 150000, 2011, 'Acción-Aventura', 'Nintendo', 'Nintendo', NULL, NULL, '2026-04-14 14:16:31', 'Wii Play: Motion es un juego tipo party con 12 minijuegos diseñados para aprovechar el sensor de movimiento avanzado (MotionPlus).\n\nEl Big Box es especial porque:\n\nIncluye el control con MotionPlus integrado\nFue pensado como “entrada” a la tecnología de movimiento\nEs más grande y llamativo (tipo edición bundle)\n🎮 Contenido del Big Box\n📀 Juego Wii Play Motion\n🎮 Wii Remote Plus oficial\n📦 Caja grande (coleccionable)', 4, 0),
(432, 'Wii Play Nintendo Wii Big Box con Wii Remote', 32, '0ae8f1c7d922ee442f49f5b38797706e', 'NTSC-U', NULL, 'Usado - Bueno', 1, 1, 1, 35000, 2006, 'Acción-Aventura', 'Nintendo', 'Nintendo/Sega', NULL, NULL, '2026-04-14 14:20:06', '¿Qué es el Big Box?\n\nEl Big Box de Wii Play es la versión especial que venía en una caja grande porque incluía:\n\n🎮 1 Wii Remote (control original)\n💿 Juego completo Wii Play\n📦 Caja grande tipo bundle\n\n👉 No era una edición limitada como tal, pero fue la versión más común al lanzamiento.\n\n📝 Descripción\n\nWii Play es un juego de minijuegos diseñado para mostrar cómo funciona el control de movimiento del Wii.\n\nIncluye 9 minijuegos, como:\n\nDisparos tipo Duck Hunt\nPesca\nBillar\nTanques\n\nFue pensado como complemento de Wii Sports, usando mecánicas similares pero más simples.', 4, 0),
(433, '16bit-Collection Data East', 24, 'ec04570e9c204315c3ba16bae64259c2', 'NTSC-J', NULL, 'Usado - Bueno', 1, 1, 1, 30000, 2017, 'Compilación', 'Data East', 'Retro-Bit', NULL, NULL, '2026-05-01 01:11:31', 'Es una colección en formato cartucho físico de 16 bits que incluye varios juegos clásicos de Data East en uno solo.\n\n👉 Cada volumen trae distintos juegos:\n\n📦 Volumen 1\nMagical Drop\nFighter’s History\nJoe & Mac\nMotteke Oh! Dorobou', 4, 0);
INSERT INTO `libros` (`id`, `id_imagen`, `titulo`, `autor`, `anio`, `editorial`, `estado`, `precio`, `comentario`, `created_at`, `calificacion`, `favorito`) VALUES
(1, '50fc6aa847ecce7063a8e498e3046913', 'La Historia de Nintendo Vol. 1', 'Florent Gorges', 2026, 'Omake Books', 'Usado - Excelente', 25000, 'Este libro no es sobre consolas como NES o Switch directamente.\n👉 Es mucho más interesante que eso:\n\n✔️ Te muestra cómo Nintendo sobrevivió más de 100 años\n✔️ Explica por qué la empresa es tan diferente a otras compañías\n✔️ Tiene fotos, documentos históricos y detalles poco conocidos\n\n❌ Si buscas algo tipo “historia de videojuegos”, puede parecer lento al inicio\n\n👉 En resumen:\nEs ideal si te gusta la historia real detrás de Nintendo, no solo los juegos.\nEspecialmente bueno si te interesa entender cómo una empresa de cartas terminó creando a Mario.', '2026-04-15 01:46:02', '⭐⭐⭐⭐⭐', 0),
(2, 'ce4dd4f0572e5b3b041028aab040ff37', 'La Historia de Nintendo Vol. 2', 'Florent Gorges', 2012, 'Omake Books', 'Usado - Excelente', 35000, 'Este volumen es donde Nintendo realmente empieza a parecerse a la empresa que conocemos hoy:\n\n✔️ Muestra el nacimiento de sus ideas más importantes\n✔️ Explica cómo pasaron de juguetes a videojuegos\n✔️ Introduce a figuras clave como Yokoi y Miyamoto\n\n❌ Puede ser muy detallado (casi tipo documental escrito)\n\n👉 En resumen:\nSi el Vol. 1 es la base histórica, este es el inicio real de Nintendo como gigante del gaming.', '2026-04-15 01:48:01', '⭐⭐⭐⭐⭐', 0),
(3, '5389899ed7d99745247a16d1ac93aff2', 'La Historia de Nintendo Vol. 3', 'Florent Gorges', 2013, 'Omake Books', 'Usado - Excelente', 40000, 'Comentario\n\nEste volumen es probablemente el más icónico:\n\n✔️ Muestra el nacimiento de casi todas las franquicias legendarias\n✔️ Explica cómo Nintendo dominó el mercado mundial\n✔️ Es el punto donde todo gamer reconoce la historia\n\n❌ Menos “curioso” que los anteriores, más enfocado en lo conocido\n\n👉 En resumen:\nEs el corazón de la historia de Nintendo. Si creciste con NES o te gusta lo retro, este tomo es casi obligatorio.', '2026-04-15 01:49:18', '⭐⭐⭐⭐⭐', 0),
(4, '89521cacea1c2dc3560e30af701705f1', 'La Historia de Nintendo Vol. 4', 'Florent Gorges', 2015, 'Omake Books', 'Usado - Excelente', 50000, 'Este tomo se centra en la evolución hacia lo portátil y la consolidación total de Nintendo 🎮\n\n🎮 Contenido principal\n🟪 Nacimiento de Game Boy (1989)\nDesarrollo liderado por Gunpei Yokoi\nFilosofía de “tecnología madura” (no lo más potente, pero sí eficiente)\n🧩 Explosión con Tetris\nÉxito mundial de Tetris en portátil\nFactor clave en la popularidad del sistema\n🧬 Fenómeno Pokémon\nLanzamiento de Pokémon Red y Blue\nAparición de Pikachu\nInicio de una de las franquicias más grandes del mundo\n🕹️ Evolución de consolas\nAvances posteriores tras NES (Game Boy y transición de generaciones)\n⚙️ Cambios internos\nImpacto de decisiones empresariales\nÚltima etapa de Yokoi en Nintendo', '2026-04-15 01:50:26', '⭐⭐⭐⭐⭐', 0);
